"use client";

import React from "react";
import { AiWorkAnnouncement } from "./announcement";
import { AiWorkHeader } from "./header";
import { AiWorkHero } from "./hero";
import { AiWorkWrapper } from "./wrapper";
import { DemoLayout } from "@/components/demo-layout";

/**
 * AI-WORK BLOCK (Page Entry)
 * Composed high-fidelity landing experience with cinematic scroll effects.
 */
export default function AiWorkPage() {
  const [isAnnouncementVisible, setIsAnnouncementVisible] = React.useState(true);

  return (
    <div className="w-full bg-accent text-foreground selection:bg-background selection:text-background font-sans">
      {/* 1. Announcement Bar */}
      <AiWorkAnnouncement
        isVisible={isAnnouncementVisible}
        onClose={() => setIsAnnouncementVisible(false)}
      />

      {/* 2. Master Content Wrapper (Handles Cinematic Layering) */}
      <AiWorkWrapper isAnnouncementVisible={isAnnouncementVisible}>

        {/* 3. Navigation Header */}
        <AiWorkHeader isScrolled={false} isFullWidth={false} />

        {/* 4. Hero Landing Section */}
        <AiWorkHero />

        {/* Additional sections can be modularly added here */}

        <DemoLayout />

      </AiWorkWrapper>
    </div>
  );
}

"use client";

import { ArrowUpRight, Asterisk } from "lucide-react";
import { Button } from "@/components/ui/button";

/**
 * AI-Work Announcement Bar
 * Precision-engineered thin bar for top-level alerts.
 */
export function AiWorkAnnouncement({
  isVisible,
  onClose
}: {
  isVisible: boolean;
  onClose: () => void;
}) {
  if (!isVisible) return null;

  return (
    <div className="sticky top-0 z-10 flex h-8 items-center justify-between bg-accent px-6 text-[10px] font-bold uppercase tracking-[0.15em] text-muted-foreground">
      <div className="flex items-center gap-2">
        <div className="h-1.5 w-1.5 animate-pulse rounded-full bg-emerald-500 shadow-[0_0_8px_rgba(16,185,129,0.8)]" />
        <p>
          Announcing <span className="text-foreground">$10M</span> Seed Funding
        </p>
      </div>
      <div className="flex items-center gap-4">
        <a
          href="#"
          className="flex items-center gap-1 transition-colors hover:text-foreground"
        >
          Read More
          <ArrowUpRight className="h-2.5 w-2.5" />
        </a>
        <Button
          variant="ghost"
          size="icon-sm"
          onClick={onClose}
          className="ml-2 transition-all hover:scale-110"
        >
          <Asterisk className="h-2.5 w-2.5 rotate-45" />
        </Button>
      </div>
    </div>
  );
}

"use client";

import React from "react";
import { Asterisk } from "lucide-react";
import { cn } from "@/lib/utils";
import { Button } from "@/components/ui/button";
import { useTheme } from "next-themes";
import { Logo } from "@/components/logo";

/**
 * AI-Work Header
 * Sticky, minimalist navigation with glassmorphism and theme toggle.
 */
export function AiWorkHeader({
  isScrolled,
  isFullWidth
}: {
  isScrolled: boolean;
  isFullWidth: boolean;
}) {
  const { theme, setTheme } = useTheme();
  const [mounted, setMounted] = React.useState(false);

  React.useEffect(() => {
    setMounted(true);
  }, []);

  const navItems = ["AI Workforce", "Platform", "Integrations", "Company"];

  // Avoid hydration mismatch by waiting for mount
  const activeScrolled = mounted ? isScrolled : false;
  const activeFullWidth = mounted ? isFullWidth : false;

  return (
    <header
      className={cn(
        "sticky top-0 z-50 flex h-16 items-center justify-between px-4 md:px-6 transition-all duration-300",
        activeScrolled
          ? "bg-transparent"
          : "bg-[radial-gradient(ellipse_80%_50%_at_50%_-10%,rgba(120,119,198,0.08),transparent)]",
        !activeFullWidth && "rounded-t-2xl"
      )}
    >
      {/* Logo */}
      <div className="flex-1 flex items-center gap-2">
        <Logo className="h-6" />
        <span className="inline-flex items-center justify-center rounded-full bg-accent/10 px-1.5 py-px text-[7px] font-black uppercase tracking-widest text-foreground ring-1 ring-inset ring-foreground/20 leading-none h-3.5">
          Pro
        </span>
      </div>

      {/* Navigation */}
      <div className="flex items-center gap-6">
        <nav className="flex items-center gap-1 rounded-full bg-secondary/30 p-1 backdrop-blur-md border border-border/50">
          {navItems.map((item) => (
            <Button
              key={item}
              variant="ghost"
              size="sm"
              className="rounded-full px-5 h-9 text-[14px] font-medium transition-all hover:bg-white/5"
            >
              {item}
            </Button>
          ))}
        </nav>

        {/* Actions */}
        <div className="flex items-center gap-4">
          <Button
            variant="secondary"
            className="h-10 rounded-full font-bold transition-all hover:scale-105 active:scale-95 px-6 text-[14px]"
          >
            Request a Demo
          </Button>
          <Button
            variant="ghost"
            size="icon"
            onClick={() => setTheme(theme === "dark" ? "light" : "dark")}
            className="group relative rounded-full ring-1 ring-border/50 transition-all hover:bg-primary/5 hover:ring-primary/40 active:scale-95 shadow-[0_0_0_rgba(var(--primary),0)] hover:shadow-[0_0_20px_rgba(var(--primary),0.15)]"
            title="Toggle Theme"
          >
            <Asterisk className="h-5 w-5 text-muted-foreground transition-all duration-500 group-hover:rotate-180 group-hover:text-primary animate-[spin_15s_linear_infinite]" />
            <span className="absolute inset-0 rounded-full bg-primary/5 opacity-0 transition-opacity group-hover:opacity-100" />
          </Button>
        </div>
      </div>
    </header>
  );
}

"use client";

import React from "react";
import { cn } from "@/lib/utils";
import { AiWorkHeader } from "./header";

/**
 * AI-Work Content Wrapper
 * Manages the scroll-sync logic and provides the "slide-over" layering context.
 */
export function AiWorkWrapper({
  children,
  isAnnouncementVisible
}: {
  children: React.ReactNode;
  isAnnouncementVisible: boolean;
}) {
  const [isScrolled, setIsScrolled] = React.useState(false);
  const [isFullWidth, setIsFullWidth] = React.useState(false);
  const [mounted, setMounted] = React.useState(false);

  React.useEffect(() => {
    setMounted(true);
    const handleScroll = () => {
      const scrollY = window.scrollY;
      // Stage 1: Full-width snap once past announcement (32px)
      setIsFullWidth(scrollY > 32 || !isAnnouncementVisible);

      // Stage 2: Transparency snap once Hero reaches middle of Header (32 + 40 = 72px)
      setIsScrolled(scrollY > 72);
    };
    window.addEventListener("scroll", handleScroll);
    handleScroll(); // Initial check
    return () => window.removeEventListener("scroll", handleScroll);
  }, [isAnnouncementVisible]);

  const activeFullWidth = mounted ? isFullWidth : false;

  return (
    <div className={cn(
      "relative z-20 bg-background transition-all duration-300 shadow-[0_-20px_80px_rgba(0,0,0,0.1)]",
      activeFullWidth
        ? "mx-0 rounded-none border-none"
        : "mx-2 rounded-t-2xl border-t border-l border-r border-border/50"
    )}>
      {React.Children.map(children, (child) => {
        if (React.isValidElement(child) && child.type === AiWorkHeader) {
          // Pass states only after mounting to prevent mismatch
          return React.cloneElement(child as React.ReactElement<any>, {
            isScrolled: mounted ? isScrolled : false,
            isFullWidth: activeFullWidth
          });
        }
        return child;
      })}
    </div>
  );
}
